import io.micrometer.tracing.*;
import org.springframework.stereotype.Service;

@Service
public class PortfolioService {
    private final Tracer tracer;
    PortfolioService(Tracer tracer) { this.tracer = tracer; }

    public double calculatePortfolioValue(String userId) {
        Span span = tracer.nextSpan()
            .name("calculate-portfolio-value")
            .tag("userId", userId)
            .start();

        try (Tracer.SpanInScope ignored = tracer.withSpan(span)) {
            // Simulate portfolio calculation:
            double value = Math.round(Math.random() * 100000) / 100.0;
            span.tag("portfolioValue", String.valueOf(value));
            span.event("calculation-complete");
            return value;
        } catch (Exception e) {
            span.error(e);
            throw e;
        } finally {
            span.end();  // ALWAYS end the span!
        }
    }
}

