# application.properties (shared):
management.zipkin.tracing.endpoint=http://zipkin:9411/api/v2/spans
spring.application.name=order-service
# traceId in logs:
logging.pattern.console=%d{HH:mm:ss} [%X{traceId}] %-5level %msg%n

# application-dev.properties:
management.tracing.sampling.probability=1.0
# 100%: see every single request's trace in Zipkin

# application-prod.properties:
management.tracing.sampling.probability=0.05
# 5%: 1 in 20 requests traced

# Math:
# 200 req/s × 0.05 (5%) = 10 traced requests/s
# 10 × 8 spans = 80 spans/s
# 80 × 3600 = 288,000 spans/hour
# Very manageable for Zipkin!

# vs 100% sampling:
# 200 × 8 × 3600 = 5,760,000 spans/hour → would need large Zipkin cluster

public class SamplingMath {
    public static void main(String[] args) {
        int reqPerSec = 200; double sampling = 0.05; int spansPerTrace = 8;
        long spansPerHour = (long)(reqPerSec * sampling * spansPerTrace * 3600);
        System.out.println("Spans/hour at 5% sampling: " + spansPerHour);
        // Output: 288000
    }
}

