exercises.expected_solution:
import io.micrometer.tracing.*;
import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

record StockData(String symbol, double price, boolean tradeable) {}

interface StockRepo {
    Optional<StockData> findBySymbol(String symbol);
}

@Service
public class InstrumentedStockService {
    private final Tracer tracer;
    private final StockRepo repo;
    private final Map<String, StockData> cache = new ConcurrentHashMap<>();

    InstrumentedStockService(Tracer tracer, StockRepo repo) {
        this.tracer = tracer; this.repo = repo;
    }

    public StockData getStock(String symbol) {
        // Check cache first:
        if (cache.containsKey(symbol)) {
            // Still create a span to show the cache hit in Zipkin:
            Span span = tracer.nextSpan().name("stock-lookup")
                .tag("symbol", symbol).tag("source", "cache").start();
            try (Tracer.SpanInScope s = tracer.withSpan(span)) {
                span.event("cache-hit");
                return cache.get(symbol);
            } finally { span.end(); }
        }

        // Cache miss — query DB:
        Span dbSpan = tracer.nextSpan().name("stock-db-query")
            .tag("symbol", symbol).tag("source", "database").start();
        long start = System.currentTimeMillis();

        try (Tracer.SpanInScope s = tracer.withSpan(dbSpan)) {
            dbSpan.event("cache-miss");
            StockData result = repo.findBySymbol(symbol)
                .orElseThrow(() -> new NoSuchElementException("Symbol not found: " + symbol));

            long elapsed = System.currentTimeMillis() - start;
            dbSpan.tag("price", String.valueOf(result.price()))
                  .tag("elapsed_ms", String.valueOf(elapsed));
            dbSpan.event("db-query-complete");

            cache.put(symbol, result);
            return result;
        } catch (Exception e) {
            dbSpan.error(e);
            throw e;
        } finally {
            dbSpan.end();
        }
    }
}

