import io.micrometer.tracing.Tracer;
import org.springframework.web.filter.OncePerRequestFilter;
import org.springframework.stereotype.Component;
import jakarta.servlet.*; import jakarta.servlet.http.*;
import java.io.IOException;

@Component
public class AuditFilter extends OncePerRequestFilter {
    private final Tracer tracer;
    AuditFilter(Tracer tracer) { this.tracer = tracer; }

    @Override
    protected void doFilterInternal(HttpServletRequest req,
                                     HttpServletResponse res,
                                     FilterChain chain)
            throws ServletException, IOException {

        // Read traceId from current span (set by Micrometer Tracing):
        String traceId = "unknown";
        if (tracer.currentSpan() != null && tracer.currentSpan().context() != null) {
            traceId = tracer.currentSpan().context().traceId();
        }

        long start = System.currentTimeMillis();
        System.out.printf("[AUDIT] %s %s | trace=%s%n",
            req.getMethod(), req.getRequestURI(), traceId);

        try {
            chain.doFilter(req, res);
        } finally {
            long elapsed = System.currentTimeMillis() - start;
            System.out.printf("[AUDIT] %s %s | status=%d | %dms | trace=%s%n",
                req.getMethod(), req.getRequestURI(),
                res.getStatus(), elapsed, traceId);
        }
    }
}

