import org.slf4j.MDC;
import org.springframework.web.filter.OncePerRequestFilter;
import org.springframework.stereotype.Component;
import jakarta.servlet.*; import jakarta.servlet.http.*;
import java.io.IOException;

@Component
public class UserContextFilter extends OncePerRequestFilter {

    @Override
    protected void doFilterInternal(HttpServletRequest req,
                                     HttpServletResponse res,
                                     FilterChain chain)
            throws ServletException, IOException {
        String userId = req.getHeader("X-User-Id");
        if (userId != null) {
            MDC.put("userId", userId);  // put in MDC before chain.doFilter
        }
        try {
            chain.doFilter(req, res);
        } finally {
            MDC.remove("userId");  // always clean up!
        }
    }
}

// Note: MDC values propagate within the same thread.
// For async operations (@Async, Feign calls), MDC must be explicitly propagated.
