import io.micrometer.tracing.*;
import org.springframework.stereotype.Service;

@Service
public class PaymentProcessor {
    private final Tracer tracer;
    PaymentProcessor(Tracer tracer) { this.tracer = tracer; }

    public String processPayment(String userId, double amount) {
        Span span = tracer.nextSpan()
            .name("process-payment")
            .tag("userId", userId)
            .tag("amount", String.valueOf(amount))
            .start();

        try (Tracer.SpanInScope s = tracer.withSpan(span)) {
            // Validation:
            if (amount > 100_000) {
                IllegalArgumentException ex =
                    new IllegalArgumentException("Amount exceeds limit: " + amount);
                span.error(ex);  // marks span as ERROR in Zipkin (RED)
                span.tag("error.reason", "amount-limit-exceeded");
                throw ex;
            }

            // Simulate gateway call:
            String paymentId = callGateway(userId, amount);

            // Success:
            span.tag("paymentId", paymentId);
            span.event("payment-confirmed");
            return paymentId;

        } catch (IllegalArgumentException e) {
            throw e;  // already marked as error above
        } catch (Exception e) {
            span.error(e);  // mark any other exception as error
            throw new RuntimeException("Payment gateway error", e);
        } finally {
            span.end();
        }
    }

    private String callGateway(String userId, double amount) {
        return "PAY-" + userId + "-" + (long)amount;
    }
}

import io.micrometer.tracing.*;
import org.springframework.stereotype.Service;
import org.springframework.web.bind.annotation.*;
import org.springframework.http.*;

// TradeController:
@RestController @RequestMapping("/api/trades")
class TradeController {
    private final Tracer tracer; private final TradeService tradeService;
    TradeController(Tracer t, TradeService s) { tracer=t; tradeService=s; }

    @PostMapping public ResponseEntity<String> trade(@RequestBody java.util.Map<String,Object> req) {
        Span span = tracer.nextSpan().name("trade-request")
            .tag("userId", String.valueOf(req.get("userId")))
            .tag("symbol", String.valueOf(req.get("symbol")))
            .tag("qty",    String.valueOf(req.get("qty")))
            .start();
        try (Tracer.SpanInScope s = tracer.withSpan(span)) {
            String result = tradeService.executeTrade(
                (String)req.get("userId"),(String)req.get("symbol"),(Integer)req.get("qty"));
            span.tag("result", result);
            return ResponseEntity.status(201).body(result);
        } catch(Exception e) { span.error(e); throw e; } finally { span.end(); }
    }
}

// TradeService:
@Service class TradeService {
    private final Tracer tracer;
    TradeService(Tracer t) { tracer=t; }
    public String executeTrade(String userId, String symbol, int qty) {
        Span span = tracer.nextSpan().name("trade-orchestration")
            .tag("userId",userId).tag("symbol",symbol).start();
        try(Tracer.SpanInScope s=tracer.withSpan(span)) {
            span.event("checking-market-quote");
            // ... Feign calls here create child spans automatically ...
            span.event("processing-payment");
            String orderId = "ORD-"+symbol+"-"+qty;
            span.tag("orderId",orderId);
            return orderId;
        } catch(Exception e){ span.error(e); throw e; } finally { span.end(); }
    }
}

