import io.micrometer.tracing.Tracer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import org.springframework.stereotype.Component;
import java.util.*;
import java.util.stream.Collectors;

@Component
public class LogCorrelationDemo {
    private static final Logger log = LoggerFactory.getLogger(LogCorrelationDemo.class);
    private final Tracer tracer;
    LogCorrelationDemo(Tracer tracer) { this.tracer = tracer; }

    // Simulate request processing across 'services':
    public List<String> simulateMultiServiceRequest(String operationName) {
        var span = tracer.nextSpan().name(operationName).start();
        List<String> capturedLogs = new ArrayList<>();

        try (Tracer.SpanInScope s = tracer.withSpan(span)) {
            String traceId = span.context().traceId();
            MDC.put("traceId", traceId);

            // Simulate order-service log:
            String log1 = String.format("[%s] order-service: Processing trade", traceId);
            capturedLogs.add(log1);
            log.info("Processing trade for {}", operationName);

            // Simulate market-service log (same traceId):
            String log2 = String.format("[%s] market-service: Fetching quote", traceId);
            capturedLogs.add(log2);
            log.info("Fetching market quote");

            // Simulate payment-service log:
            String log3 = String.format("[%s] payment-service: Processing payment", traceId);
            capturedLogs.add(log3);

            return capturedLogs;
        } finally {
            MDC.remove("traceId");
            span.end();
        }
    }

    // Filter logs by traceId (simulates 'grep traceId=abc123 *.log'):
    public static List<String> filterByTraceId(List<String> allLogs, String traceId) {
        return allLogs.stream()
            .filter(line -> line.contains(traceId))
            .collect(Collectors.toList());
    }
}

import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.context.TestPropertySource;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.NONE)
@TestPropertySource(properties="eureka.client.enabled=false")
class LogCorrelationTest {
    @Autowired LogCorrelationDemo demo;
    @Autowired Tracer tracer;

    @Test void allLogsHaveSameTraceId() {
        List<String> logs = demo.simulateMultiServiceRequest("test-trade");
        assertEquals(3, logs.size());
        // All logs contain the same traceId:
        String firstTraceId = logs.get(0).split("\\[")[1].split("\\]")[0];
        logs.forEach(line -> assertTrue(line.contains(firstTraceId),
            "Expected traceId " + firstTraceId + " in: " + line));
    }

    @Test void filterByTraceId_returnsOnlyMatchingLogs() {
        List<String> allLogs = List.of(
            "[abc123] order-service: trade",
            "[xyz789] order-service: other trade",
            "[abc123] market-service: quote");
        var filtered = LogCorrelationDemo.filterByTraceId(allLogs, "abc123");
        assertEquals(2, filtered.size());
        assertTrue(filtered.stream().allMatch(l -> l.contains("abc123")));
    }
}

